1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_SIZE = 3;
4	const BLOCK_BASE_PREMIUM = 60;
5	
6	// Main items are insured individually at their base premium.
7	const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	// Components are grouped by type; exactly BLOCK_SIZE alike components
15	// form a "block" with a fixed base premium instead of per-item pricing.
16	const COMPONENT_BASE_PREMIUMS: Record<string, number> = {
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const isComponent = (itemType: string): boolean =>
22	  itemType in COMPONENT_BASE_PREMIUMS;
23	
24	const countByType = (items: { type: string }[]): Record<string, number> =>
25	  items.reduce<Record<string, number>>((counts, item) => {
26	    counts[item.type] = (counts[item.type] ?? 0) + 1;
27	    return counts;
28	  }, {});
29	
30	const componentGroupPremium = (componentType: string, count: number): number => {
31	  const perItem = COMPONENT_BASE_PREMIUMS[componentType];
32	  return count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * perItem;
33	};
34	
35	const computeBasePremium = (items: { type: string }[]): number => {
36	  const counts = countByType(items);
37	  return Object.entries(counts).reduce((total, [type, count]) => {
38	    if (isComponent(type)) {
39	      return total + componentGroupPremium(type, count);
40	    }
41	    return total + count * (MAIN_ITEM_BASE_PREMIUMS[type] ?? 0);
42	  }, 0);
43	};
44	
45	const CURSED_SURCHARGE_RATE = 0.5;
46	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
47	const HIGH_ENCHANTMENT_THRESHOLD = 5;
48	
49	const computeItemSurcharges = (
50	  items: { type: string; cursed?: boolean; enchantment?: number }[],
51	): number =>
52	  items.reduce((total, item) => {
53	    if (!(item.type in MAIN_ITEM_BASE_PREMIUMS)) {
54	      return total;
55	    }
56	    const base = MAIN_ITEM_BASE_PREMIUMS[item.type];
57	    let surcharge = 0;
58	    if (item.cursed) {
59	      surcharge += base * CURSED_SURCHARGE_RATE;
60	    }
61	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
62	      surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
63	    }
64	    return total + surcharge;
65	  }, 0);
66	
67	const LOYALTY_DISCOUNT_RATE = 0.2;
68	const LOYALTY_THRESHOLD_YEARS = 2;
69	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
70	
71	type PremiumContext = {
72	  items: { type: string; cursed?: boolean; enchantment?: number }[];
73	  isLoyalCustomer: boolean;
74	  isFollowUpContract: boolean;
75	};
76	
77	const computeStepPremium = (context: PremiumContext): number => {
78	  const basePremium = computeBasePremium(context.items);
79	  const itemSurcharges = computeItemSurcharges(context.items);
80	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
81	  const loyaltyDiscount = context.isLoyalCustomer
82	    ? basePremium * LOYALTY_DISCOUNT_RATE
83	    : 0;
84	  const followUpDiscount = context.isFollowUpContract
85	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
86	    : 0;
87	  return (
88	    basePremium +
89	    itemSurcharges +
90	    firstInsuranceSurcharge -
91	    loyaltyDiscount -
92	    followUpDiscount +
93	    PROCESSING_FEE
94	  );
95	};
96	
97	const INSURANCE_VALUES: Record<string, number> = {
98	  sword: 1000,
99	  amulet: 600,
100	  staff: 800,
101	  potion: 400,
102	  rune: 250,
103	  moonstone: 250,
104	};
105	
106	const DEDUCTIBLE_PER_DAMAGE = 100;
107	const CAP_MULTIPLIER = 2;
108	
109	type PolicyItem = { type: string; enchantment?: number };
110	
111	type PolicyState = {
112	  items: PolicyItem[];
113	  remainingCap: number;
114	};
115	
116	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
117	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
118	
119	const computeInsuranceSum = (items: { type: string }[]): number =>
120	  items.reduce((total, item) => total + (INSURANCE_VALUES[item.type] ?? 0), 0);
121	
122	const computeDamagePayout = (
123	  damage: { itemType: string; amount: number },
124	  items: PolicyItem[],
125	): number => {
126	  const item = items.find((i) => i.type === damage.itemType);
127	  const reimbursable =
128	    item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
129	      ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
130	      : damage.amount;
131	  return reimbursable - DEDUCTIBLE_PER_DAMAGE;
132	};
133	
134	const computeClaimPayout = (
135	  damages: { itemType: string; amount: number }[],
136	  items: PolicyItem[],
137	): number =>
138	  damages.reduce((total, damage) => total + computeDamagePayout(damage, items), 0);
139	
140	type QuoteContext = {
141	  items: { type: string; cursed?: boolean; enchantment?: number }[];
142	  isLoyalCustomer: boolean;
143	  isFollowUpContract: boolean;
144	};
145	
146	const handleQuote = (
147	  step: any,
148	  index: number,
149	  policies: Record<number, PolicyState>,
150	  isLoyalCustomer: boolean,
151	): { premium: number } => {
152	  const items = step?.items ?? [];
153	  policies[index] = {
154	    items,
155	    remainingCap: computeInsuranceSum(items) * CAP_MULTIPLIER,
156	  };
157	  const context: QuoteContext = {
158	    items,
159	    isLoyalCustomer,
160	    isFollowUpContract: index > 0,
161	  };
162	  return { premium: Math.ceil(computeStepPremium(context)) };
163	};
164	
165	const handleClaim = (
166	  step: any,
167	  policies: Record<number, PolicyState>,
168	): { payout: number; remainingCap: number } => {
169	  const policy = policies[step.policy];
170	  const damages = step?.incident?.damages ?? [];
171	  const payout = computeClaimPayout(damages, policy.items);
172	  policy.remainingCap -= payout;
173	  return { payout, remainingCap: policy.remainingCap };
174	};
175	
176	export const runScenario = (scenario: any): unknown => {
177	  const steps = scenario?.steps ?? [];
178	  const isLoyalCustomer =
179	    (scenario?.customer?.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS;
180	  const policies: Record<number, PolicyState> = {};
181	  const results = steps.map((step: any, index: number) =>
182	    step?.op === "claim"
183	      ? handleClaim(step, policies)
184	      : handleQuote(step, index, policies, isLoyalCustomer),
185	  );
186	  return { results };
187	};
